// WalletCarousel.js - Carrusel que vuelve al inicio al llegar al final

import React, { useState, useEffect } from 'react';
import WalletCard from './WalletCard';
import './WalletCarousel.css';

const WalletCarousel = ({ wallets }) => {
  const [currentGroup, setCurrentGroup] = useState(0);
  const [cardsPerView, setCardsPerView] = useState(3);
  
  // Detectar tamaño de pantalla
  useEffect(() => {
    const handleResize = () => {
      if (window.innerWidth < 640) {
        setCardsPerView(1);
      } else if (window.innerWidth < 1024) {
        setCardsPerView(2);
      } else {
        setCardsPerView(3);
      }
    };
    
    handleResize();
    window.addEventListener('resize', handleResize);
    return () => window.removeEventListener('resize', handleResize);
  }, []);
  
  // Calcular grupos de billeteras
  const totalGroups = Math.ceil(wallets.length / cardsPerView);
  
  // Obtener las billeteras visibles según el grupo actual
  const getVisibleWallets = () => {
    const start = currentGroup * cardsPerView;
    const end = start + cardsPerView;
    return wallets.slice(start, end);
  };
  
  const goToPrevious = () => {
    setCurrentGroup(prev => {
      if (prev === 0) {
        // Si estamos al inicio, vamos al último grupo
        return totalGroups - 1;
      }
      return prev - 1;
    });
  };
  
  const goToNext = () => {
    setCurrentGroup(prev => {
      if (prev === totalGroups - 1) {
        // Si estamos al final, volvemos al primer grupo
        return 0;
      }
      return prev + 1;
    });
  };
  
  const goToGroup = (index) => {
    setCurrentGroup(index);
  };
  
  const visibleWallets = getVisibleWallets();
  
  return (
    <div className="carousel-wrapper">
      <div className="carousel-container">
        <button className="carousel-nav-btn prev" onClick={goToPrevious}>
          <span className="nav-icon">←</span>
        </button>
        
        <div className="carousel-viewport">
          <div className="carousel-track-simple">
            {visibleWallets.map((wallet) => (
              <div key={wallet.id} className="carousel-slide-simple">
                <WalletCard
                  name={wallet.name}
                  type={wallet.type}
                  balance={wallet.balance}
                />
              </div>
            ))}
          </div>
        </div>
        
        <button className="carousel-nav-btn next" onClick={goToNext}>
          <span className="nav-icon">→</span>
        </button>
      </div>
      
      {/* Dots indicadores */}
      <div className="carousel-dots">
        {Array.from({ length: totalGroups }).map((_, idx) => (
          <button
            key={idx}
            className={`carousel-dot ${currentGroup === idx ? 'active' : ''}`}
            onClick={() => goToGroup(idx)}
          />
        ))}
      </div>
    </div>
  );
};

export default WalletCarousel;
